from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson.objectid import ObjectId
import os
import re

app = Flask(__name__)

# Securely load MongoDB credentials
MONGO_USER = os.getenv('MONGO_USER')
MONGO_PASS = os.getenv('MONGO_PASS')
MONGO_DB = os.getenv('MONGO_DB', 'cms')
MONGO_URI = f"mongodb://{MONGO_USER}:{MONGO_PASS}@localhost:27017/{MONGO_DB}"

# Connect to MongoDB
client = MongoClient(MONGO_URI)
db = client[MONGO_DB]
profiles_collection = db['user_profiles']

# Helper function to validate input
def validate_input(data):
    if not isinstance(data, dict):
        raise ValueError("Invalid input format")
    for key, value in data.items():
        if not re.match(r'^[a-zA-Z0-9_]+$', key):
            raise ValueError("Invalid key format")
        if not isinstance(value, (str, int, float, list, dict)):
            raise ValueError("Invalid value type")

@app.route('/profiles', methods=['POST'])
def create_profile():
    try:
        data = request.json
        validate_input(data)
        result = profiles_collection.insert_one(data)
        return jsonify({'id': str(result.inserted_id)}), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@app.route('/profiles/<profile_id>', methods=['GET'])
def get_profile(profile_id):
    try:
        profile = profiles_collection.find_one({'_id': ObjectId(profile_id)})
        if not profile:
            return jsonify({'error': 'Profile not found'}), 404
        profile['_id'] = str(profile['_id'])
        return jsonify(profile), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@app.route('/profiles', methods=['GET'])
def query_profiles():
    try:
        query = request.args.to_dict()
        validate_input(query)
        profiles = profiles_collection.find(query)
        result = [{**profile, '_id': str(profile['_id'])} for profile in profiles]
        return jsonify(result), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400

@app.route('/profiles/aggregate', methods=['POST'])
def aggregate_profiles():
    try:
        pipeline = request.json
        if not isinstance(pipeline, list):
            raise ValueError("Invalid pipeline format")
        result = profiles_collection.aggregate(pipeline)
        result_list = [{**doc, '_id': str(doc['_id'])} for doc in result]
        return jsonify(result_list), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=False)